 53			return http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 54				startedAt := now()
 55				requestID := incomingRequestID(r, newRequestID)
 56	
 57				w.Header().Set(requestIDHeader, requestID)
 58				ctx := context.WithValue(r.Context(), requestIDContextKey{}, requestID)
 59				ctx = logger.ContextWithRequestCorrelation(ctx, requestID, r.Header.Get("Traceparent"))
 60				r = r.WithContext(ctx)
 61	
 62				recorder := &requestBoundaryWriter{
 63					ResponseWriter: w,
 64					statusCode:     http.StatusOK,
 65				}
 66	
 67				defer func() {
 68					if recovered := recover(); recovered != nil {
 69						if !recorder.wroteHeader {
 70							writeRecoveredPanicResponse(recorder)
 71						} else {
 72							recorder.statusCode = http.StatusInternalServerError
 73						}
 74	
 75						runtimeLogger.Error(
 76							"middleware",
 77							"request panic recovered",
 78							errors.New("panic recovered"),
 79							requestBoundaryFields(r, requestID, recorder.statusCode, now().Sub(startedAt), "panic")...,
 80						)
 81					}
 82				}()
 83	
 84				next.ServeHTTP(recorder, r)
 85	
 86				fields := requestBoundaryFields(r, requestID, recorder.statusCode, now().Sub(startedAt), "")
 87	
 88				switch {
 89				case recorder.statusCode >= http.StatusInternalServerError:
 90					runtimeLogger.Error("middleware", "request failed", nil, fields...)
 91				case recorder.statusCode >= http.StatusBadRequest:
 92					runtimeLogger.Warn("middleware", "request completed with client error", fields...)
 93				default:
 94					runtimeLogger.Info("middleware", "request completed", fields...)
 95				}
 96			})
 97		}
 98	}
