100	func requestBoundaryFields(r *http.Request, requestID string, statusCode int, duration time.Duration, errorType string) []logger.Field {
101		fields := []logger.Field{
102			logger.Operation("RequestBoundary"),
103			logger.RequestID(requestID),
104			logger.Method(requestMethod(r)),
105			logger.Path(requestPath(r)),
106			logger.StatusCode(statusCode),
107			logger.DurationMS(duration),
108		}
109		if address := strings.TrimSpace(getClientIP(r)); address != "" {
110			fields = append(fields, logger.Address(address))
111		}
112		fields = append(fields, logger.TraceContextFromTraceparent(r.Header.Get("Traceparent"))...)
113		if strings.TrimSpace(errorType) != "" {
114			fields = append(fields, logger.ErrorType(errorType))
115		}
116	
117		return fields
118	}
