120	func writeRecoveredPanicResponse(w http.ResponseWriter) {
121		w.Header().Set("Content-Type", "application/json")
122		w.WriteHeader(http.StatusInternalServerError)
123		_ = json.NewEncoder(w).Encode(struct {
124			OK     bool   `json:"ok"`
125			Reason string `json:"reason"`
126		}{
127			OK:     false,
128			Reason: "INTERNAL_ERROR",
129		})
130	}
