 48	// ContextWithRequestCorrelation attaches the request-boundary correlation fields
 49	// used by runtime logging and legacy handler diagnostics.
 50	func ContextWithRequestCorrelation(ctx context.Context, requestID, traceparent string) context.Context {
 51		if ctx == nil {
 52			ctx = context.Background()
 53		}
 54	
 55		requestID = strings.TrimSpace(requestID)
 56		if requestID != "" {
 57			ctx = context.WithValue(ctx, requestIDContextKey, requestID)
 58		}
 59	
 60		traceID, spanID := parseTraceparent(traceparent)
 61		if traceID != "" {
 62			ctx = context.WithValue(ctx, traceIDContextKey, traceID)
 63		}
 64		if spanID != "" {
 65			ctx = context.WithValue(ctx, spanIDContextKey, spanID)
 66		}
 67	
 68		return ctx
 69	}
