 15	func TestRequestBoundaryMiddlewareAddsContextHeaderAndStructuredLog(t *testing.T) {
 16		var buffer bytes.Buffer
 17	
 18		timestamps := []time.Time{
 19			time.Unix(1_710_000_000, 0).UTC(),
 20			time.Unix(1_710_000_000, 0).UTC().Add(1500 * time.Millisecond),
 21		}
 22		nowCalls := 0
 23		now := func() time.Time {
 24			current := timestamps[nowCalls]
 25			nowCalls++
 26			return current
 27		}
 28	
 29		var seenRequestID string
 30		var seenLoggerRequestID string
 31		middleware := newRequestBoundaryMiddleware(logger.New(&buffer), now, func() string {
 32			return "req-123"
 33		})
 34	
 35		handler := middleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
 36			seenRequestID = RequestIDFromContext(r.Context())
 37			seenLoggerRequestID = logger.RequestIDFromContext(r.Context())
 38			w.WriteHeader(http.StatusCreated)
 39			_, _ = w.Write([]byte("created"))
 40		}))
 41	
 42		req := httptest.NewRequest(http.MethodGet, "/observed?token=abc123", nil)
 43		req.Header.Set("Traceparent", "00-4bf92f3577b34da6a3ce929d0e0e4736-00f067aa0ba902b7-01")
 44		req.Header.Set("X-Forwarded-For", "198.51.100.10")
 45		rec := httptest.NewRecorder()
 46	
 47		handler.ServeHTTP(rec, req)
 48	
 49		if seenRequestID != "req-123" {
 50			t.Fatalf("expected request ID in context, got %q", seenRequestID)
 51		}
 52		if seenLoggerRequestID != "req-123" {
 53			t.Fatalf("expected logger request ID in context, got %q", seenLoggerRequestID)
 54		}
 55		if got := rec.Header().Get(requestIDHeader); got != "req-123" {
 56			t.Fatalf("expected response request ID header req-123, got %q", got)
 57		}
 58	
 59		output := buffer.String()
 60		for _, want := range []string{
 61			"level=INFO",
 62			`component="middleware"`,
 63			`msg="request completed"`,
 64			`operation="RequestBoundary"`,
 65			`request_id="req-123"`,
 66			`trace_id="4bf92f3577b34da6a3ce929d0e0e4736"`,
 67			`span_id="00f067aa0ba902b7"`,
 68			`trace_flags="01"`,
 69			`method="GET"`,
 70			`path="/observed"`,
 71			`status_code="201"`,
 72			`duration_ms="1500"`,
 73			`address="198.51.100.10"`,
 74		} {
 75			if !strings.Contains(output, want) {
 76				t.Fatalf("expected %q in output, got %q", want, output)
 77			}
 78		}
 79		if strings.Contains(output, "abc123") {
 80			t.Fatalf("expected query secrets to stay out of request log output, got %q", output)
 81		}
 82	}
