 84	func TestRequestBoundaryMiddlewareRecoversPanicWithSanitizedCorrelatedFailure(t *testing.T) {
 85		var buffer bytes.Buffer
 86	
 87		timestamps := []time.Time{
 88			time.Unix(1_710_000_000, 0).UTC(),
 89			time.Unix(1_710_000_000, 0).UTC().Add(25 * time.Millisecond),
 90		}
 91		nowCalls := 0
 92		now := func() time.Time {
 93			current := timestamps[nowCalls]
 94			nowCalls++
 95			return current
 96		}
 97	
 98		middleware := newRequestBoundaryMiddleware(logger.New(&buffer), now, func() string {
 99			return "req-generated"
100		})
101		handler := middleware(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
102			panic("password=swordfish")
103		}))
104	
105		req := httptest.NewRequest(http.MethodPost, "/v0/panic?token=abc123", nil)
106		req.Header.Set(logger.RequestIDHeader, "req-client")
107		req.Header.Set("Traceparent", "00-4bf92f3577b34da6a3ce929d0e0e4736-00f067aa0ba902b7-01")
108		rec := httptest.NewRecorder()
109	
110		handler.ServeHTTP(rec, req)
111	
112		if rec.Code != http.StatusInternalServerError {
113			t.Fatalf("expected status 500, got %d", rec.Code)
114		}
115		if got := rec.Header().Get(logger.RequestIDHeader); got != "req-client" {
116			t.Fatalf("expected preserved request ID header, got %q", got)
117		}
118		if got := rec.Header().Get("Content-Type"); got != "application/json" {
119			t.Fatalf("expected JSON content type, got %q", got)
120		}
121	
122		var response struct {
123			OK     bool   `json:"ok"`
124			Reason string `json:"reason"`
125		}
126		if err := json.Unmarshal(rec.Body.Bytes(), &response); err != nil {
127			t.Fatalf("decode panic response: %v", err)
128		}
129		if response.OK || response.Reason != "INTERNAL_ERROR" {
130			t.Fatalf("expected sanitized internal error response, got %+v", response)
131		}
132		if strings.Contains(rec.Body.String(), "swordfish") {
133			t.Fatalf("expected panic detail to stay out of client body, got %q", rec.Body.String())
134		}
135	
136		output := buffer.String()
137		for _, want := range []string{
138			"level=ERROR",
139			`component="middleware"`,
140			`msg="request panic recovered"`,
141			`operation="RequestBoundary"`,
142			`request_id="req-client"`,
143			`trace_id="4bf92f3577b34da6a3ce929d0e0e4736"`,
144			`span_id="00f067aa0ba902b7"`,
145			`status_code="500"`,
146			`duration_ms="25"`,
147			`error_type="panic"`,
148		} {
149			if !strings.Contains(output, want) {
150				t.Fatalf("expected %q in output, got %q", want, output)
151			}
152		}
153		for _, forbidden := range []string{"swordfish", "abc123"} {
154			if strings.Contains(output, forbidden) {
155				t.Fatalf("expected sensitive value %q to stay out of logs, got %q", forbidden, output)
156			}
157		}
158	}
